public static SalesTable createSalesTable(AgreementReference _agreementReference,PurchId _purchId)
{
    SalesAgreementHeader        salesAgreementHeader;      
    ETG_SalesAgreementHeader    salesAgreementHeaderTrade;

    SalesTable              salesTable;
    CustTable               custTable;
    CustAccount             custAccount;
    NumberSeq               numberSeq;
    SalesId                 salesID;
    try
    {
        select firstonly * from salesAgreementHeader
            where salesAgreementHeader.RecId == _agreementReference.DerivedAgreement
        join salesAgreementHeaderTrade
            where salesAgreementHeaderTrade.SalesAgreementId == salesAgreementHeader.SalesNumberSequence;

        salesTable.clear();
        numberSeq = NumberSeq::newGetNum(SalesParameters::numRefSalesId());
        numberSeq.used();
        salesTable.SalesId = numberSeq.num();
        salesID = salesTable.SalesId;

        salesTable.initValue();

        salesTable.CustAccount = salesAgreementHeader.CustAccount;            
        salesTable.initFromCustTable();
        salesTable.InterCompanyCompanyId = curExt();
        salesTable.InterCompanyPurchId   = _purchId;
        salesTable.InterCompanyOrder     =  NoYes::Yes;  
        salesTable.SkipUpdate            = InterCompanySkipUpdate::Both;
        salesTable.insert();
        ETG_CreateSalesOrder::createSalesTrade(salesTable.SalesId,salesAgreementHeaderTrade);
        info(strFmt('Third party sales order %1 created successfully',salesTable.SalesId));

    }
    catch(Exception::Error)
    {
        ttsabort;
    }

    return salesTable;
}

public static void createSalesTrade(SalesId _salesId,ETG_SalesAgreementHeader _salesAgreementHeaderTrade)
{       
    ETG_SalesTableTrade            salesTableTrade;
    ETG_SalesAgreementNotes        salesAgreementNotes;
    ETG_SalesAgreementQualityGrp   SalesAgreementQualityGrp;
    ETG_SalesTableNotes            salesTableNotes;
    ETG_SalesTableQualityGrp       salesQtyGrp;

    salesTableTrade.SalesId                           = _salesId;
    salesTableTrade.AdvanceDue                        = _salesAgreementHeaderTrade.AdvanceDue;
    salesTableTrade.BuyerAccountNum                   = _salesAgreementHeaderTrade.BuyerAccountNum;
    salesTableTrade.BuyerDeliveryAddress              = _salesAgreementHeaderTrade.BuyerDeliveryAddress;
    salesTableTrade.BuyerBank                         = _salesAgreementHeaderTrade.BuyerBank;
    salesTableTrade.SellerAccountNum                  = _salesAgreementHeaderTrade.SellerAccountNum;
    salesTableTrade.SellerBank                        = _salesAgreementHeaderTrade.SellerBank;
    salesTableTrade.SellerDeliveryAddress             = _salesAgreementHeaderTrade.SellerDeliveryAddress;
 //   salesTableTrade.CommissionType                    = _salesAgreementHeaderTrade.CommissionType;
    salesTableTrade.Consignee                         = _salesAgreementHeaderTrade.Consignee;
    salesTableTrade.CustomImport                      = _salesAgreementHeaderTrade.CustomImport;
    salesTableTrade.DeliveryDescription               = _salesAgreementHeaderTrade.DeliveryDescription;
//    salesTableTrade.DisplayTotalCalculatedCommission  = _salesAgreementHeaderTrade.DisplayTotalCalculatedCommission;
    salesTableTrade.FromDatePort                      = _salesAgreementHeaderTrade.FromDatePort;
    salesTableTrade.Future                            = _salesAgreementHeaderTrade.Future;
    salesTableTrade.ImportDate                        = _salesAgreementHeaderTrade.ImportDate;
    salesTableTrade.Notes                             = _salesAgreementHeaderTrade.Notes;
    salesTableTrade.Notifytodifferentparty            = _salesAgreementHeaderTrade.Notifytodifferentparty;
    salesTableTrade.Number                            = _salesAgreementHeaderTrade.Number;
    salesTableTrade.OnAccountOf                       = _salesAgreementHeaderTrade.OnAccountOf;
    salesTableTrade.PortOfDischarge                   = _salesAgreementHeaderTrade.PortOfDischarge;
    salesTableTrade.PortOfLoading                     = _salesAgreementHeaderTrade.PortOfLoading;
    salesTableTrade.PricingFromDate                   = _salesAgreementHeaderTrade.PricingFromDate;
    salesTableTrade.PricingMonth                      = _salesAgreementHeaderTrade.PricingMonth;
    salesTableTrade.PricingTodate                     = _salesAgreementHeaderTrade.PricingTodate;
    salesTableTrade.TermPaymDescription               = _salesAgreementHeaderTrade.TermPaymDescription;
    salesTableTrade.TermsOfDelDescription             = _salesAgreementHeaderTrade.TermsOfDelDescription;
    salesTableTrade.QuantityConditions                = _salesAgreementHeaderTrade.QuantityConditions;
    salesTableTrade.Through                           = _salesAgreementHeaderTrade.Through;
    salesTableTrade.ToDatePort                        = _salesAgreementHeaderTrade.ToDatePort;
   // salesTableTrade.TypeValue                         = _salesAgreementHeaderTrade.TypeValue;
    salesTableTrade.Buyersecondarybank                = _salesAgreementHeaderTrade.Buyersecondarybank;
    salesTableTrade.Sellersecondarybank               = _salesAgreementHeaderTrade.Sellersecondarybank;
    salesTableTrade.PortOfDischargeDesc               = _salesAgreementHeaderTrade.PortOfDischargeDesc;
    salesTableTrade.PortOfLoadingDesc                 = _salesAgreementHeaderTrade.PortOfLoadingDesc;
    salesTableTrade.Name                              = _salesAgreementHeaderTrade.Name;
    salesTableTrade.Address                           = _salesAgreementHeaderTrade.Address;
    salesTableTrade.insert();

    while select EnumNotes,Description from salesAgreementNotes
            where salesAgreementNotes.SalesAgreementId == _salesAgreementHeaderTrade.SalesAgreementId
    {
        salesTableNotes.SalesId          = _salesId;
        salesTableNotes.EnumNotes        = salesAgreementNotes.EnumNotes;
        salesTableNotes.Description      = salesAgreementNotes.Description;
        salesTableNotes.insert();
    }

    while select GroupId from SalesAgreementQualityGrp
        where SalesAgreementQualityGrp.SalesAgreementId == _salesAgreementHeaderTrade.SalesAgreementId
    {
        salesQtyGrp.SalesId  = _salesId;
        salesQtyGrp.GroupId  = SalesAgreementQualityGrp.GroupId;
        salesQtyGrp.insert();
    }
}

