public static SalesLine createSalesLine(AgreementLineQuantityCommitment _agreementLine,PurchLine _purchLine)
{
    SalesLine               salesLine;
    ETG_SalesLineNotes      salesLineNotes;
    ETG_AgreementLineNotes  agreementLineNotes;
    SalesTable              salesTable = SalesTable::find(_purchLine.purchTable().InterCompanySalesId);

    salesLine.SalesId       = salesTable.SalesId;
    salesLine.initFromSalesTable(salesTable);
    salesLine.initFromAgreementLine(_agreementLine);
    salesLine.ItemId            = _agreementLine.ItemId;
    salesLine.SalesQty          = _purchLine.PurchQty;
    salesLine.itemIdChanged();
    salesLine.SalesPrice        = _agreementLine.PricePerUnit;        
    salesLine.LineAmount        = salesLine.calcLineAmount(salesLine.SalesQty);
  //  salesLine.InterCompanyInventTransId = _purchLine.InventTransId;
   // salesLine.InterCompanyOrigin        =   InterCompanyOrigin:;
  //  salesLine.SkipUpdate                = InterCompanySkipUpdate::Both;
    salesLine.insert();

    while select EnumNotes,Description,ItemId from agreementLineNotes
            where agreementLineNotes.AgreementLine == _agreementLine.RecId
    {
        salesLineNotes.InventTransId = salesLine.InventTransId;
        salesLineNotes.EnumNotes     = agreementLineNotes.EnumNotes;
        salesLineNotes.Description   = agreementLineNotes.Description;
        salesLineNotes.ItemId        = agreementLineNotes.ItemId;
        salesLineNotes.insert();
    }

    return salesLine;
}

public static PurchTable createPurchTable(AgreementReference _agreementReference,SalesId _salesId)
{
    PurchAgreementHeader            purchAgreementHeader;
    ETG_PurchaseAgreementHeader     purchAgreementHeaderTrade;

    PurchTable              purchTable;
    VendTable               vendTable;
    NumberSeq               numberSeq;

    try
    {
        select firstonly * from purchAgreementHeader
            where purchAgreementHeader.RecId == _agreementReference.DerivedAgreement
        join purchAgreementHeaderTrade
            where purchAgreementHeaderTrade.PurchAgreementId == purchAgreementHeader.PurchNumberSequence;

        purchTable.clear();
        numberSeq = NumberSeq::newGetNum(PurchParameters::numRefPurchaseOrderId());
        numberSeq.used();
        purchTable.PurchId = numberSeq.num();

        purchTable.initValue();
        vendTable               = VendTable::find(purchAgreementHeader.VendAccount);
        purchTable.OrderAccount = purchAgreementHeader.VendAccount;
        purchTable.initFromVendTable(vendTable);
        purchTable.InterCompanyCompanyId = curExt();
        purchTable.InterCompanySalesId   = _salesId;
        purchTable.InterCompanyOrder     =  NoYes::Yes;
        purchTable.SkipUpdate            = InterCompanySkipUpdate::Both;
        purchTable.insert();
        ETG_CreateSalesOrder::createPurchTrade(purchTable.PurchId,purchAgreementHeaderTrade);
        info(strFmt('Third party purchase order %1 created successfully',purchTable.PurchId));

    }
    catch(Exception::Error)
    {
        ttsabort;
    }

    return purchTable;
}

public static PurchLine createPurchLine(AgreementLineQuantityCommitment _agreementLine,SalesLine _salesLine)
{
    PurchLine               purchLine;
    ETG_PurchLineNotes      purchLineNotes;
    ETG_AgreementLineNotes  agreementLineNotes;
    PurchTable              purchTable = PurchTable::find(_salesLine.salesTable().SalesId);

    purchLine.PurchId       = purchTable.PurchId;
    purchLine.initFromPurchTable(purchTable);
    purchLine.initFromAgreementLine(_agreementLine);
    purchLine.ItemId            = _agreementLine.ItemId;
    purchLine.PurchQty          = _salesLine.SalesQty;
    purchLine.itemIdChanged();
    purchLine.PurchPrice        = _agreementLine.PricePerUnit;     
    purchLine.LineAmount        = purchLine.calcLineAmount(purchLine.PurchQty);
    purchLine.InterCompanyInventTransId = _salesLine.InventTransId;
    purchLine.InterCompanyOrigin        = InterCompanyOrigin::Derived;
    purchLine.createLine(true,false,false,false,false,false);

    while select EnumNotes,Description,ItemId from agreementLineNotes
         where agreementLineNotes.AgreementLine == _agreementLine.RecId
    {
        purchLineNotes.InventTransId = purchLine.InventTransId;
        purchLineNotes.EnumNotes     = agreementLineNotes.EnumNotes;
        purchLineNotes.Description   = agreementLineNotes.Description;
        purchLineNotes.ItemId        = agreementLineNotes.ItemId;
        purchLineNotes.insert();
    }

    return purchLine;
}
